#include <pthread.h>
#include <stdio.h>

void* thread_function(void* data) {
 printf("Thread executed with data: %s\n", (char*)data);
 return NULL;
}

int main() {
 pthread_t thread;
 char* data = "Hello from thread";

 // Create a new thread
 pthread_create(&thread, NULL, thread_function, (void*)data);

 // Wait for the thread to finish
 pthread_join(thread, NULL);

 return 0;
}
